import React, { useEffect, useState } from 'react';
import { View, Button, Text } from 'react-native';
import { authorize, refresh } from 'react-native-app-auth';
import AsyncStorage from '@react-native-async-storage/async-storage';

const config = {
  issuer: 'YOUR_OAUTH_SERVER_URL',
  clientId: 'YOUR_CLIENT_ID',
  clientSecret: 'YOUR_CLIENT_SECRET', 
  redirectUrl: 'com.yourapp:/callback',
  scopes: ['openid', 'profile', 'email'],
};

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  const handleLogin = async () => {
    try {
      const result = await authorize(config);

      setAccessToken(result.accessToken);

      // Store the tokens in secure storage
      await AsyncStorage.setItem('access_token', result.accessToken);
      await AsyncStorage.setItem('refresh_token', result.refreshToken);
    } catch (error) {
      console.error('Failed to log in', error);
    }
  };

  const handleRefreshToken = async () => {
    const refreshToken = await AsyncStorage.getItem('refresh_token');

    try {
      const result = await refresh(config, {
        refreshToken: refreshToken,
      });

      setAccessToken(result.accessToken);

      // Update the new access token in secure storage
      await AsyncStorage.setItem('access_token', result.accessToken);
    } catch (error) {
      console.error('Failed to refresh token', error);
    }
  };

  useEffect(() => {
    const checkForToken = async () => {
      const token = await AsyncStorage.getItem('access_token');

      if (token) {
        setAccessToken(token);
      }
    };

    checkForToken();
  }, []);

  return (
    <View>
      {accessToken ? (
        <Text>You are logged in!</Text>
      ) : (
        <Button title="Login" onPress={handleLogin} />
      )}
      <Button title="Refresh Token" onPress={handleRefreshToken} disabled={!accessToken} />
    </View>
  );
};

export default App;